#include <iostream>
#include <cstring>
#include <cstdio> 
using namespace std;
int main()
{
	string x,h;
	int hs=1,xs=1,i;
	getline(cin,h);
	getline(cin,x);
	for(i=0;i<h.size();i++)
	{
		hs*=(h[i]-'@');
	}
	for(i=0;i<x.size();i++)
	{
		xs*=(x[i]-'@');
	}
	if(hs%47==xs%47)
		cout<<"GO";
	else
		cout<<"STAY";
	return 0;
}
